pub const Setup = struct {
    status: u8,
    protocol_major_version: u16,
    protocol_minor_version: u16,
    length: u16,
    release_number: u32,
    resource_id_base: u32,
    resource_id_mask: u32,
    motion_buffer_size: u32,
    maximum_request_length: u16,
    image_byte_order: ImageOrder,
    bitmap_format_bit_order: ImageOrder,
    bitmap_format_scanline_unit: u8,
    bitmap_format_scanline_pad: u8,
    min_keycode: u8,
    max_keycode: u8,
    vendor: []const u8,
    pixmap_formats: []FORMAT,
    roots: []SCREEN,

    pub fn byteLen(self: @This()) usize {
        return 1 + 1 + 2 + 2 + 2 + 4 + 4 + 4 + 4 + 2 + 2 + 1 + 1 + 1 + 1 + 1 + 1 + 1 + 1 + 4 + self.vendor.len + wire.pad4(self.vendor.len) + wire.structListByteLen(self.pixmap_formats) + wire.structListByteLen(self.roots);
    }

    pub fn encode(self: @This(), writer: *std.Io.Writer) EncodeError!void {
        try writer.writeByte(self.status);
        try writer.splatByteAll(0, 1);
        try writer.writeInt(u16, self.protocol_major_version, .little);
        try writer.writeInt(u16, self.protocol_minor_version, .little);
        try writer.writeInt(u16, self.length, .little);
        try writer.writeInt(u32, self.release_number, .little);
        try writer.writeInt(u32, self.resource_id_base, .little);
        try writer.writeInt(u32, self.resource_id_mask, .little);
        try writer.writeInt(u32, self.motion_buffer_size, .little);
        try writer.writeInt(u16, @intCast(self.vendor.len), .little);
        try writer.writeInt(u16, self.maximum_request_length, .little);
        try writer.writeByte(@intCast(self.roots.len));
        try writer.writeByte(@intCast(self.pixmap_formats.len));
        try writer.writeByte(@intCast(@intFromEnum(self.image_byte_order)));
        try writer.writeByte(@intCast(@intFromEnum(self.bitmap_format_bit_order)));
        try writer.writeByte(self.bitmap_format_scanline_unit);
        try writer.writeByte(self.bitmap_format_scanline_pad);
        try writer.writeByte(self.min_keycode);
        try writer.writeByte(self.max_keycode);
        try writer.splatByteAll(0, 4);
        try writer.writeAll(self.vendor);
        try writer.splatByteAll(0, wire.pad4(self.vendor.len));
        for (self.pixmap_formats) |elem| {
            try elem.encode(writer);
        }
        for (self.roots) |elem| {
            try elem.encode(writer);
        }
    }

    pub fn decode(allocator: std.mem.Allocator, reader: *std.Io.Reader) AllocDecodeError!@This() {
        const status = try reader.takeByte();
        _ = try reader.take(1);
        const protocol_major_version = try reader.takeInt(u16, .little);
        const protocol_minor_version = try reader.takeInt(u16, .little);
        const length = try reader.takeInt(u16, .little);
        const release_number = try reader.takeInt(u32, .little);
        const resource_id_base = try reader.takeInt(u32, .little);
        const resource_id_mask = try reader.takeInt(u32, .little);
        const motion_buffer_size = try reader.takeInt(u32, .little);
        const vendor_len = try reader.takeInt(u16, .little);
        const maximum_request_length = try reader.takeInt(u16, .little);
        const roots_len = try reader.takeByte();
        const pixmap_formats_len = try reader.takeByte();
        const image_byte_order = @as(ImageOrder, @enumFromInt(try reader.takeInt(u8, .little)));
        const bitmap_format_bit_order = @as(ImageOrder, @enumFromInt(try reader.takeInt(u8, .little)));
        const bitmap_format_scanline_unit = try reader.takeByte();
        const bitmap_format_scanline_pad = try reader.takeByte();
        const min_keycode = try reader.takeByte();
        const max_keycode = try reader.takeByte();
        _ = try reader.take(4);
        const vendor_byte_len = @as(usize, vendor_len);
        const vendor_temp = try reader.take(vendor_byte_len);
        const vendor = try allocator.dupe(u8, vendor_temp);
        _ = try reader.take(wire.pad4(vendor.len));
        const pixmap_formats = try allocator.alloc(FORMAT, @as(usize, pixmap_formats_len));
        errdefer allocator.free(pixmap_formats);
        var pixmap_formats_decoded: usize = 0;
        for (pixmap_formats) |*elem| {
            const elem_value = try FORMAT.decode(reader);
            elem.* = elem_value;
            pixmap_formats_decoded += 1;
        }
        const roots = try allocator.alloc(SCREEN, @as(usize, roots_len));
        errdefer allocator.free(roots);
        var roots_decoded: usize = 0;
        errdefer for (roots[0..roots_decoded]) |*elem| elem.deinit(allocator);
        for (roots) |*elem| {
            const elem_value = try SCREEN.decode(allocator, reader);
            elem.* = elem_value;
            roots_decoded += 1;
        }
        return .{
            .status = status,
            .protocol_major_version = protocol_major_version,
            .protocol_minor_version = protocol_minor_version,
            .length = length,
            .release_number = release_number,
            .resource_id_base = resource_id_base,
            .resource_id_mask = resource_id_mask,
            .motion_buffer_size = motion_buffer_size,
            .maximum_request_length = maximum_request_length,
            .image_byte_order = image_byte_order,
            .bitmap_format_bit_order = bitmap_format_bit_order,
            .bitmap_format_scanline_unit = bitmap_format_scanline_unit,
            .bitmap_format_scanline_pad = bitmap_format_scanline_pad,
            .min_keycode = min_keycode,
            .max_keycode = max_keycode,
            .vendor = vendor,
            .pixmap_formats = pixmap_formats,
            .roots = roots,
        };
    }

    pub fn deinit(self: *@This(), allocator: std.mem.Allocator) void {
        allocator.free(self.vendor);
        allocator.free(self.pixmap_formats);
        for (self.roots) |*elem| elem.deinit(allocator);
        allocator.free(self.roots);
    }

};

