    pub const extension: ?extensions.Extension = null;
    pub const Reply = InternAtomReply;

    only_if_exists: bool,
    name: []const u8,

    pub fn byteLen(self: @This()) usize {
        return 2 + 2 + self.name.len;
    }

    pub fn headerByte1(self: @This()) u8 {
        return @intFromBool(self.only_if_exists);
    }

    pub fn encode(self: @This(), writer: *std.Io.Writer) EncodeError!void {
        try writer.writeInt(u16, @intCast(self.name.len), .little);
        try writer.splatByteAll(0, 2);
        try writer.writeAll(self.name);
    }

};

