    pub const extension: ?extensions.Extension = null;
    pub const Reply = void;

    coordinate_mode: CoordMode,
    drawable: Drawable,
    gc: Gcontext,
    points: []const POINT,

    pub fn byteLen(self: @This()) usize {
        return 4 + 4 + wire.structListByteLen(self.points);
    }

    pub fn headerByte1(self: @This()) u8 {
        return @intCast(@intFromEnum(self.coordinate_mode));
    }

    pub fn encode(self: @This(), writer: *std.Io.Writer) EncodeError!void {
        try self.drawable.encode(writer);
        try writer.writeInt(u32, @intFromEnum(self.gc), .little);
        for (self.points) |elem| {
            try elem.encode(writer);
        }
    }

};

