            .window = window,
            .colormap = colormap,
            .new = new,
            .state = state,
        };
    }
};

pub const ClientMessageEvent = struct {
    format: u8,
    window: Window,
    type: Atom,
    data: ClientMessageData,

    pub fn toBytes(self: @This()) EncodeError![32]u8 {
        var packet: [32]u8 = std.mem.zeroes([32]u8);
        var writer_impl: std.Io.Writer = .fixed(&packet);
        const writer = &writer_impl;
        try writer.writeByte(33);
        try writer.writeByte(self.format);
        try writer.writeInt(u16, 0, .little);
        try writer.writeInt(u32, @intFromEnum(self.window), .little);
        try writer.writeInt(u32, @intFromEnum(self.type), .little);
        try self.data.encode(writer);
        return packet;
    }

    pub fn decode(reader: *std.Io.Reader) DecodeError!@This() {
        _ = try reader.takeByte();
        const format = try reader.takeByte();
        _ = try reader.takeInt(u16, .little);
        const window = @as(Window, @enumFromInt(try reader.takeInt(u32, .little)));
        const @"type" = @as(Atom, @enumFromInt(try reader.takeInt(u32, .little)));
        const data = try ClientMessageData.decode(reader);
        return .{
            .format = format,
            .window = window,
            .type = @"type",
            .data = data,
        };
    }
};

pub const MappingNotifyEvent = struct {
    request: Mapping,
    first_keycode: u8,
    count: u8,

    pub fn toBytes(self: @This()) EncodeError![32]u8 {
        var packet: [32]u8 = std.mem.zeroes([32]u8);
        var writer_impl: std.Io.Writer = .fixed(&packet);
        const writer = &writer_impl;
        try writer.writeByte(34);
        try writer.writeByte(0);
        try writer.writeInt(u16, 0, .little);
        try writer.writeByte(@intCast(@intFromEnum(self.request)));
        try writer.writeByte(self.first_keycode);
        try writer.writeByte(self.count);
        try writer.splatByteAll(0, 1);
        return packet;
    }

    pub fn decode(reader: *std.Io.Reader) DecodeError!@This() {
        _ = try reader.takeByte();
        _ = try reader.take(1);
        _ = try reader.takeInt(u16, .little);
        const request = @as(Mapping, @enumFromInt(try reader.takeInt(u8, .little)));
        const first_keycode = try reader.takeByte();
        const count = try reader.takeByte();
        _ = try reader.take(1);
        return .{
            .request = request,
            .first_keycode = first_keycode,
            .count = count,
        };
    }
};

pub const GeGenericEvent = struct {
    extension: u8,
    length: u32,
    event_type: u16,
    full_sequence: u32,

    pub fn toBytes(self: @This()) EncodeError![32]u8 {
        var packet: [32]u8 = std.mem.zeroes([32]u8);
        var writer_impl: std.Io.Writer = .fixed(&packet);
        const writer = &writer_impl;
        try writer.writeByte(35);
        try writer.writeByte(self.extension);
        try writer.writeInt(u16, 0, .little);
        try writer.writeInt(u32, self.length, .little);
        try writer.writeInt(u16, self.event_type, .little);
        try writer.writeInt(u16, 0, .little);
        try writer.writeInt(u32, self.full_sequence, .little);
        return packet;
    }

    pub fn decode(reader: *std.Io.Reader) DecodeError!@This() {
        _ = try reader.takeByte();
        const extension = try reader.takeByte();
        _ = try reader.takeInt(u16, .little);
        const length = try reader.takeInt(u32, .little);
        const event_type = try reader.takeInt(u16, .little);
        _ = try reader.take(2);
        const full_sequence = try reader.takeInt(u32, .little);
        _ = try reader.take(16);
        _ = try reader.take(@as(usize, length) * 4);
        return .{
            .extension = extension,
            .length = length,
            .event_type = event_type,
            .full_sequence = full_sequence,
        };
    }
};

pub const UnknownEvent = struct {
    code: u8,
    sequence: u16,
    raw: [32]u8,
};

pub const Event = union(enum) {
    unknown: UnknownEvent,
    KeyPress: KeyPressEvent,
    KeyRelease: KeyReleaseEvent,
    ButtonPress: ButtonPressEvent,
    ButtonRelease: ButtonReleaseEvent,
    MotionNotify: MotionNotifyEvent,
    EnterNotify: EnterNotifyEvent,
    LeaveNotify: LeaveNotifyEvent,
    FocusIn: FocusInEvent,
    FocusOut: FocusOutEvent,
    KeymapNotify: KeymapNotifyEvent,
    Expose: ExposeEvent,
    GraphicsExposure: GraphicsExposureEvent,
    NoExposure: NoExposureEvent,
    VisibilityNotify: VisibilityNotifyEvent,
    CreateNotify: CreateNotifyEvent,
    DestroyNotify: DestroyNotifyEvent,
    UnmapNotify: UnmapNotifyEvent,
    MapNotify: MapNotifyEvent,
    MapRequest: MapRequestEvent,
    ReparentNotify: ReparentNotifyEvent,
    ConfigureNotify: ConfigureNotifyEvent,
    ConfigureRequest: ConfigureRequestEvent,
    GravityNotify: GravityNotifyEvent,
    ResizeRequest: ResizeRequestEvent,
    CirculateNotify: CirculateNotifyEvent,
    CirculateRequest: CirculateRequestEvent,
    PropertyNotify: PropertyNotifyEvent,
    SelectionClear: SelectionClearEvent,
    SelectionRequest: SelectionRequestEvent,
    SelectionNotify: SelectionNotifyEvent,
    ColormapNotify: ColormapNotifyEvent,
    ClientMessage: ClientMessageEvent,
    MappingNotify: MappingNotifyEvent,
    GeGeneric: GeGenericEvent,
};

pub fn decodeEvent(reader: *std.Io.Reader) DecodeError!Event {
    const code = (try reader.peek(1))[0] & 0x7f;
    return switch (code) {
        2 => .{ .KeyPress = try KeyPressEvent.decode(reader) },
        3 => .{ .KeyRelease = try KeyReleaseEvent.decode(reader) },
        4 => .{ .ButtonPress = try ButtonPressEvent.decode(reader) },
        5 => .{ .ButtonRelease = try ButtonReleaseEvent.decode(reader) },
        6 => .{ .MotionNotify = try MotionNotifyEvent.decode(reader) },
        7 => .{ .EnterNotify = try EnterNotifyEvent.decode(reader) },
        8 => .{ .LeaveNotify = try LeaveNotifyEvent.decode(reader) },
        9 => .{ .FocusIn = try FocusInEvent.decode(reader) },
        10 => .{ .FocusOut = try FocusOutEvent.decode(reader) },
        11 => .{ .KeymapNotify = try KeymapNotifyEvent.decode(reader) },
        12 => .{ .Expose = try ExposeEvent.decode(reader) },
        13 => .{ .GraphicsExposure = try GraphicsExposureEvent.decode(reader) },
        14 => .{ .NoExposure = try NoExposureEvent.decode(reader) },
        15 => .{ .VisibilityNotify = try VisibilityNotifyEvent.decode(reader) },
        16 => .{ .CreateNotify = try CreateNotifyEvent.decode(reader) },
        17 => .{ .DestroyNotify = try DestroyNotifyEvent.decode(reader) },
        18 => .{ .UnmapNotify = try UnmapNotifyEvent.decode(reader) },
        19 => .{ .MapNotify = try MapNotifyEvent.decode(reader) },
        20 => .{ .MapRequest = try MapRequestEvent.decode(reader) },
        21 => .{ .ReparentNotify = try ReparentNotifyEvent.decode(reader) },
        22 => .{ .ConfigureNotify = try ConfigureNotifyEvent.decode(reader) },
        23 => .{ .ConfigureRequest = try ConfigureRequestEvent.decode(reader) },
        24 => .{ .GravityNotify = try GravityNotifyEvent.decode(reader) },
        25 => .{ .ResizeRequest = try ResizeRequestEvent.decode(reader) },
        26 => .{ .CirculateNotify = try CirculateNotifyEvent.decode(reader) },
        27 => .{ .CirculateRequest = try CirculateRequestEvent.decode(reader) },
        28 => .{ .PropertyNotify = try PropertyNotifyEvent.decode(reader) },
        29 => .{ .SelectionClear = try SelectionClearEvent.decode(reader) },
        30 => .{ .SelectionRequest = try SelectionRequestEvent.decode(reader) },
        31 => .{ .SelectionNotify = try SelectionNotifyEvent.decode(reader) },
        32 => .{ .ColormapNotify = try ColormapNotifyEvent.decode(reader) },
        33 => .{ .ClientMessage = try ClientMessageEvent.decode(reader) },
        34 => .{ .MappingNotify = try MappingNotifyEvent.decode(reader) },
        35 => .{ .GeGeneric = try GeGenericEvent.decode(reader) },
        else => blk: {
            const packet = try reader.take(32);
            var raw: [32]u8 = undefined;
            @memcpy(raw[0..], packet);
            break :blk .{ .unknown = .{
                .code = packet[0] & 0x7f,
                .sequence = std.mem.readInt(u16, packet[2..4], .little),
                .raw = raw,
            } };
        },
    };
}

